#include <stdio.h>
#include <string.h>

int expand(const char *s, int n, int left, int right) {
    while (left >= 0 && right < n && s[left] == s[right]) {
        left--;
        right++;
    }
    return right - left - 1; // length of palindrome
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char s[1005]; scanf("%s", s);
        int best = 0;
        for (int i = 0; i < N; ++i) {
            int len1 = expand(s, N, i, i);       // odd length
            int len2 = expand(s, N, i, i + 1);   // even length
            if (len1 > best) best = len1;
            if (len2 > best) best = len2;
        }
        printf("%d\n", best);
    }
    return 0;
}

