#include <bits/stdc++.h>
using namespace std;

int expand(const string &s, int left, int right) {
    int n = s.size();
    while (left >= 0 && right < n && s[left] == s[right]) {
        --left; ++right;
    }
    return right - left - 1; // length
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        int N; cin >> N;
        string s; cin >> s;
        int best = 0;
        for (int i = 0; i < N; ++i) {
            best = max(best, expand(s, i, i));       // odd
            best = max(best, expand(s, i, i+1));     // even
        }
        cout << best << '\n';
    }
    return 0;
}

